const localeFiles = Object.keys(TRANSLATIONS).map((code) => ({
  code,
  path: resolve(LOCALES_DIR, `${code}.json`),
}));

let totalUpdates = 0;
for (const { code, path } of localeFiles) {
  const raw = await readFile(path, "utf8");
  const data = JSON.parse(raw);
  if (!data.protocol) data.protocol = {};
  const before = JSON.stringify(data.protocol);
  for (const [key, value] of Object.entries(TRANSLATIONS[code])) {
    data.protocol[key] = value;
  }
  const after = JSON.stringify(data.protocol);
  if (before !== after) {
    await writeFile(path, JSON.stringify(data, null, 2) + "\n", "utf8");
    totalUpdates += 1;
    console.log(`translate-protocol: updated ${code}.json`);
  }
}

console.log(`translate-protocol: ${totalUpdates} locale(s) updated.`);
